import React, { useState } from 'react'
import { X } from 'lucide-react'

const CATEGORIES = ['chicken', 'burger', 'combo', 'drink', 'side', 'dessert']

const EMPTY_FORM = {
  name: '',
  description: '',
  price: '',
  image: '',
  category: 'chicken',
  cookingTime: 0,
}

export default function MenuFormModal({ isOpen, onClose, onSubmit }) {
  const [form, setForm] = useState(EMPTY_FORM)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [error, setError] = useState('')

  if (!isOpen) return null

  const handleChange = (e) => {
    const { name, value } = e.target
    setForm(prev => ({ ...prev, [name]: value }))
  }

  const handleSubmit = async () => {
    setError('')
    if (!form.name.trim()) return setError('Name is required')
    if (!form.price || isNaN(form.price) || Number(form.price) <= 0) return setError('Please enter a valid price')
    if (!form.category) return setError('Category is required')

    try {
      setIsSubmitting(true)
      await onSubmit({
        name: form.name.trim(),
        description: form.description.trim(),
        price: Number(form.price),
        image: form.image.trim(),
        category: form.category,
        cookingTime: Number(form.cookingTime) || 0,
      })
      setForm(EMPTY_FORM)
      onClose()
    } catch (err) {
      setError(err.message || 'Failed to create menu item')
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
      <div className="bg-white rounded-xl w-full max-w-md shadow-xl">

        <div className="flex items-center justify-between px-6 py-4 border-b border-brand-border-outer">
          <h2 className="text-[16px] font-bold text-brand-text-primary">Add New Menu Item</h2>
          <button onClick={onClose} className="text-brand-text-tertiary hover:text-brand-text-primary transition-colors">
            <X size={20} />
          </button>
        </div>

        <div className="px-6 py-4 flex flex-col gap-4">

          <div className="flex flex-col gap-1">
            <label className="text-[12px] font-bold text-brand-text-secondary uppercase tracking-wider">Name *</label>
            <input
              name="name"
              value={form.name}
              onChange={handleChange}
              placeholder="e.g. Spicy Chicken Sandwich"
              className="w-full px-3 py-2 border border-brand-border-outer rounded-lg text-[13px] outline-none focus:border-brand-text-tertiary"
            />
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-[12px] font-bold text-brand-text-secondary uppercase tracking-wider">Description</label>
            <input
              name="description"
              value={form.description}
              onChange={handleChange}
              placeholder="Short description"
              className="w-full px-3 py-2 border border-brand-border-outer rounded-lg text-[13px] outline-none focus:border-brand-text-tertiary"
            />
          </div>

          <div className="flex gap-3">
            <div className="flex flex-col gap-1 flex-1">
              <label className="text-[12px] font-bold text-brand-text-secondary uppercase tracking-wider">Price (เธฟ) *</label>
              <input
                name="price"
                type="number"
                value={form.price}
                onChange={handleChange}
                placeholder="0"
                min="0"
                className="w-full px-3 py-2 border border-brand-border-outer rounded-lg text-[13px] outline-none focus:border-brand-text-tertiary"
              />
            </div>
            <div className="flex flex-col gap-1 flex-1">
              <label className="text-[12px] font-bold text-brand-text-secondary uppercase tracking-wider">Category *</label>
              <select
                name="category"
                value={form.category}
                onChange={handleChange}
                className="w-full px-3 py-2 border border-brand-border-outer rounded-lg text-[13px] outline-none focus:border-brand-text-tertiary bg-white"
              >
                {CATEGORIES.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-[12px] font-bold text-brand-text-secondary uppercase tracking-wider">Image URL</label>
            <input
              name="image"
              value={form.image}
              onChange={handleChange}
              placeholder="https://... (leave empty for now)"
              className="w-full px-3 py-2 border border-brand-border-outer rounded-lg text-[13px] outline-none focus:border-brand-text-tertiary"
            />
          </div>

          <div className="flex flex-col gap-1">
            <label className="text-[12px] font-bold text-brand-text-secondary uppercase tracking-wider">Cooking Time (seconds)</label>
            <input
              name="cookingTime"
              type="number"
              value={form.cookingTime}
              onChange={handleChange}
              placeholder="0"
              min="0"
              className="w-full px-3 py-2 border border-brand-border-outer rounded-lg text-[13px] outline-none focus:border-brand-text-tertiary"
            />
          </div>

          {error && (
            <p className="text-[12px] text-red-500 font-medium">{error}</p>
          )}
        </div>

        <div className="px-6 py-4 border-t border-brand-border-outer flex gap-3">
          <button
            onClick={onClose}
            className="flex-1 px-4 py-2 border border-brand-border-outer rounded-lg text-[13px] font-medium text-brand-text-primary hover:bg-brand-sidebar transition-colors"
          >
            Cancel
          </button>
          <button
            onClick={handleSubmit}
            disabled={isSubmitting}
            className="flex-1 px-4 py-2 bg-brand-text-dark text-white rounded-lg text-[13px] font-medium hover:bg-brand-text-dark/90 transition-colors disabled:opacity-50"
          >
            {isSubmitting ? 'Saving...' : 'Add Item'}
          </button>
        </div>
      </div>
    </div>
  )
}

import React, { useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { OrdersContext } from '../../context/ordersContext/OrdersContext';

const DeliveryHistory = () => {
  const navigate = useNavigate();
  const { orderList } = useContext(OrdersContext);

  // Filter only delivered delivery orders
  const historyTasks = orderList.filter(order => 
    order.type === "delivery" && order.status === "delivered"
  );

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen shadow-lg font-sans">
      {/* Header */}
      <header className="py-8 px-4 flex items-center">
        <button 
          onClick={() => navigate('/driver')}
          className="w-10 h-10 flex items-center justify-center bg-gray-100 rounded-full text-black hover:bg-gray-200 transition-all"
        >
          โ
        </button>
        <h1 className="text-2xl font-black uppercase tracking-tight text-black ml-4">
          Delivery History
        </h1>
      </header>

      {/* Stats Summary */}
      <div className="px-6 mb-6">
        <div className="bg-black text-white rounded-[2rem] p-6 shadow-xl flex justify-between items-center">
          <div>
            <p className="text-[10px] font-black uppercase opacity-60 mb-1 tracking-widest">Total Deliveries</p>
            <p className="text-4xl font-black">{historyTasks.length}</p>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-black uppercase opacity-60 mb-1 tracking-widest">Total Earnings</p>
            <p className="text-2xl font-black">
              เธฟ{historyTasks.reduce((total, task) => 
                total + task.orderList.reduce((acc, item) => acc + (item.price * item.quantity), 0), 0
              ).toLocaleString()}
            </p>
          </div>
        </div>
      </div>

      {/* History List */}
      <div className="p-4 space-y-4 bg-gray-50/50 min-h-[70vh] rounded-t-[3rem]">
        <div className="flex justify-between items-center px-4 pt-2">
          <h2 className="text-sm font-black uppercase text-gray-400">Past Orders</h2>
          <span className="text-[10px] font-bold text-gray-400">{historyTasks.length} Completed</span>
        </div>

        {historyTasks.length > 0 ? (
          historyTasks.map((task) => {
            const displayImage = task.orderList[0]?.image || "/images/placeholder.png";
            const totalPrice = task.orderList.reduce((acc, item) => acc + (item.price * item.quantity), 0);

            // Format date if available
            const orderDate = task.orderList[0]?.orderTime;
            const formattedDate = orderDate instanceof Date 
              ? orderDate.toLocaleDateString('th-TH', { day: 'numeric', month: 'short', year: '2-digit' })
              : "Recent";

            return (
              <div 
                key={task.id} 
                className="bg-white border-2 border-gray-100 rounded-[2.5rem] p-5 shadow-sm transition-all hover:border-black group"
                onClick={() => navigate(`/driver/order/${task.id}`)}
              >
                <div className="flex items-center">
                  {/* Image */}
                  <img 
                    src={displayImage} 
                    alt={`Order ${task.id}`}
                    className="w-16 h-16 bg-gray-100 rounded-2xl flex-shrink-0 object-cover group-hover:scale-105 transition-transform"
                  />

                  {/* Details */}
                  <div className="ml-4 flex-1">
                    <div className="flex justify-between items-start">
                      <h3 className="text-sm font-black uppercase text-black">
                        #{task.id}
                      </h3>
                      <span className="text-[9px] font-black text-gray-400">
                        {formattedDate}
                      </span>
                    </div>
                    <p className="text-xs font-bold text-gray-700 mt-0.5">
                      {task.customer?.name}
                    </p>
                    <div className="flex justify-between items-end mt-2">
                      <p className="text-[9px] text-gray-400 font-bold uppercase">
                        {task.orderList.length} Items
                      </p>
                      <p className="text-sm font-black text-[#D33131]">
                        เธฟ{totalPrice.toLocaleString()}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="flex flex-col items-center justify-center py-20 text-gray-300">
            <span className="text-5xl mb-4">๐</span>
            <p className="font-bold uppercase text-xs tracking-widest">No history yet</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default DeliveryHistory;

