          <div className="p-6 pb-4 flex flex-col md:flex-row justify-between items-center gap-4">
            <div className="flex items-center gap-2 overflow-x-auto no-scrollbar w-full md:w-auto">
              {categories.map(cat => (
                <button
                  key={cat}
