const LoginModal = ({ isOpen, onClose }) => {
  const { setMyUserInfo } = useContext(UserContext);
  const [isLoading, setIsLoading] = useState(false);
  const [loginText, setLoginText] = useState("");
  const [inputUsername, setInputUsername] = useState("");
  const [inputPassword, setInputPassword] = useState("");

  if (!isOpen) return null;

  const handleLogin = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setLoginText("");

    try {
      const user = await loginAPI(inputUsername, inputPassword);
      setMyUserInfo(user);
      // เธฅเนเธญเธเธญเธดเธเธชเธณเน€เธฃเนเธเนเธ Modal: เนเธเนเธเธดเธ” Modal เนเธกเนเธ•เนเธญเธ Redirect เนเธเนเธซเธ
      // เธฅเธนเธเธเนเธฒเธเธฐเนเธ”เนเธญเธขเธนเนเธซเธเนเธฒเน€เธ”เธดเธกเน€เธเธทเนเธญเธเธ”เธชเธฑเนเธเธ•เนเธญเนเธ”เนเน€เธฅเธข
      onClose();
    } catch (error) {
