import React, { useState, useEffect, useContext, useRef } from "react";
import { Link, useNavigate } from "react-router-dom";
import {
  ShoppingCart,
  User,
  LogOut,
  Settings,
  History,
  LayoutDashboard,
} from "lucide-react";
import Logo from "../assets/picture/Logo.png";
import Slogan from "../assets/picture/slogan.png";

// Import Context
import { UserContext } from "../context/userContext/UserContext";
import { useShop } from "../context/ShopProvider";

const Navbarmenu = () => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const navigate = useNavigate();

  // เธ”เธถเธ Context เธกเธฒเนเธเนเธเธฒเธ
  const { myUserInfo, setMyUserInfo } = useContext(UserContext);
  const { cartCount, setIsCartOpen } = useShop();

  // function เธเธฅเธดเธเธเธทเนเธเธ—เธตเนเธงเนเธฒเธเธเธดเธ” dropdown profile เนเธ”เน
  const profileRef = useRef(null);
  
  // 1. เธ”เธฑเธเธเธฑเธเธเธฒเธฃเธเธฅเธดเธเน€เธกเนเธฒเธชเนเธเธเธซเธเนเธฒเธเธญ
  useEffect(() => {
    const handleClickOutside = (event) => {
      // 2. เธ–เนเธฒเธเธฅเธดเธเธเธญเธเธเธฅเนเธญเธ profileRef เนเธซเนเธเธดเธ” Dropdown
      if (profileRef.current && !profileRef.current.contains(event.target)) {
        setIsProfileOpen(false);
      }
    };

    // 3. Event Listener เนเธซเนเธฃเธญเธเธฑเธเธเธฒเธฃเธเธฅเธดเธ
    document.addEventListener("mousedown", handleClickOutside);

    // 4. เธเธฅเธตเธเธญเธฑเธเน€เธกเธทเนเธญเธญเธญเธเธเธฒเธเธซเธเนเธฒเน€เธงเนเธ
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, []);

  // Rules of Hooks: Conditional return must come AFTER all hooks
  if (myUserInfo?.role === "cook"||myUserInfo?.role === "rider") return null;

  const handleLogout = () => {
    // 1. เธฅเนเธฒเธเธเนเธญเธกเธนเธฅเนเธ Context
    setMyUserInfo(null);

    // 2. เธเธดเธ” UI เธ•เนเธฒเธเน
