import React, { useContext } from "react";
import { Navigate } from "react-router-dom";
import { UserContext } from "../context/userContext/UserContext"; // เน€เธเนเธ path เธเธตเนเนเธซเนเธ•เธฃเธเธเธฑเธเนเธเธฅเน€เธ”เธญเธฃเนเธเธฃเธดเธเธเธญเธเธเธธเธ“เธ”เนเธงเธขเธเธฐเธเธฃเธฑเธ

const ProtectedRoute = ({ children, allowedRoles }) => {
  const { myUserInfo } = useContext(UserContext);

  // 1. เธ–เนเธฒเธขเธฑเธเนเธกเนเนเธ”เนเธฅเนเธญเธเธญเธดเธ เนเธซเนเน€เธ•เธฐเธเธฅเธฑเธเนเธเธซเธเนเธฒ Login
  if (!myUserInfo) {
    return <Navigate to="/login" replace />;
  }

  // 2. เธ–เนเธฒเธฅเนเธญเธเธญเธดเธเนเธฅเนเธง เน€เธเนเธ Role
  // (เธ–เนเธฒเน€เธเนเธเนเธซเธกเธ” Dev เธซเธฃเธทเธญเธกเธต Role dev เธเธฅเนเธญเธขเธเนเธฒเธเนเธ”เนเน€เธฅเธข เธซเธฃเธทเธญเธเธฐเนเธเนเน€เธเนเธเธ•เธฒเธก Role เธเธเธ•เธด)
  if (allowedRoles && !allowedRoles.includes(myUserInfo.role)) {
    // If user is a cook, always redirect to cookBoard
    if (myUserInfo.role === "cook") {
      return <Navigate to="/cookBoard" replace />;
    }
    // เนเธซเนเน€เธ•เธฐเธเธฅเธฑเธเนเธเธซเธเนเธฒ Index/Home
    return <Navigate to="/" replace />;
  }

  // 3. เธ–เนเธฒเธฅเนเธญเธเธญเธดเธเนเธฅเนเธง เนเธฅเธฐ Role เธ–เธนเธเธ•เนเธญเธ เนเธซเนเนเธชเธ”เธเธเธฅเธซเธเนเธฒเธเธญเธ•เธฒเธกเธเธเธ•เธด
  return children;
};

export default ProtectedRoute;

