import React, { useRef, useEffect } from "react";

export default function InteractivePoolGrid({ children }) {
  const containerRef = useRef(null);
  const canvasRef = useRef(null);

  useEffect(() => {
    const container = containerRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    let animationFrameId;

    // เน€เธเนเธ•เธเธเธฒเธ” Canvas เนเธซเนเน€เธ•เนเธกเธเธฅเนเธญเธ
    let width = (canvas.width = container.offsetWidth);
    let height = (canvas.height = container.offsetHeight);

    // เน€เธเนเธเธ•เธณเนเธซเธเนเธเน€เธกเธฒเธชเน (เน€เธเนเธฒเธซเธกเธฒเธข เนเธฅเธฐ เธ•เธณเนเธซเธเนเธเธเธฑเธเธเธธเธเธฑเธเธชเธณเธซเธฃเธฑเธเธ—เธณเธชเธกเธนเธ—เธ•เธตเน)
    let mouse = { x: -1000, y: -1000, targetX: -1000, targetY: -1000 };

    const handleMouseMove = (e) => {
      const rect = container.getBoundingClientRect();
      mouse.targetX = e.clientX - rect.left;
      mouse.targetY = e.clientY - rect.top;
    };

    const handleMouseLeave = () => {
      // เน€เธญเธฒเน€เธกเธฒเธชเนเธญเธญเธเธเธธเนเธ เน€เธญเธฒเน€เธเนเธฒเธซเธกเธฒเธขเนเธเธเนเธญเธเนเธเธฅเน เธฅเธฒเธขเน€เธชเนเธเธเธฐเนเธ”เนเน€เธ”เนเธเธเธฅเธฑเธเธ—เธตเนเน€เธ”เธดเธก
      mouse.targetX = -1000;
      mouse.targetY = -1000;
    };

    const handleResize = () => {
      width = canvas.width = container.offsetWidth;
      height = canvas.height = container.offsetHeight;
    };

    container.addEventListener("mousemove", handleMouseMove);
    container.addEventListener("mouseleave", handleMouseLeave);
    window.addEventListener("resize", handleResize);

    // โ”€โ”€โ”€ ๐จ เธฅเธญเธเธดเธเธเธฒเธฃเธงเธฒเธ”เน€เธชเนเธ (Render Loop) โ”€โ”€โ”€
    const render = () => {
      // 1. เธ—เธณเนเธซเนเน€เธกเธฒเธชเนเธ•เธฒเธกเนเธเธเธซเธเนเธงเธเน (Easing) เธ”เธนเน€เธเนเธเธเธฃเธฃเธกเธเธฒเธ•เธดเธเธถเนเธ
      mouse.x += (mouse.targetX - mouse.x) * 0.1;
      mouse.y += (mouse.targetY - mouse.y) * 0.1;

      // เธฅเนเธฒเธเธซเธเนเธฒเธเธญเธเนเธญเธเธงเธฒเธ”เน€เธเธฃเธกเนเธซเธกเน
      ctx.clearRect(0, 0, width, height);

      // เธ•เธฑเนเธเธเนเธฒเธชเธตเน€เธชเนเธเธ•เธฒเธฃเธฒเธ (เธชเธตเน€เธ—เธฒเน€เธเนเธกเนเธเธฃเนเธเนเธช)
      ctx.strokeStyle = "rgba(36, 36, 36, 0.12)";
      ctx.lineWidth = 1.5;

      const spacing = 60; // เธเธงเธฒเธกเธเธงเนเธฒเธเธเธญเธเธเนเธญเธเธ•เธฒเธฃเธฒเธ
      const radius = 120; // เธฃเธฑเธจเธกเธตเธงเธเธเธฅเธกเธ—เธตเนเน€เธกเธฒเธชเนเธเธฐเนเธเธ”เธฑเธเน€เธชเนเธ
      const tension = 0.4; // เธเธงเธฒเธกเนเธฃเธเนเธเธเธฒเธฃเธ”เธฑเธเน€เธชเนเธ

      // โ”€โ”€โ”€ เธงเธฒเธ”เน€เธชเนเธเนเธเธงเธเธญเธ โ”€โ”€โ”€
      for (let y = 0; y <= height + spacing; y += spacing) {
        ctx.beginPath();
        for (let x = 0; x <= width + 20; x += 20) {
          // เธงเธฒเธ”เธเธธเธ”เธ•เนเธญเธเธธเธ”เธ—เธธเธเน 20px
          let dx = mouse.x - x;
          let dy = mouse.y - y;
          let dist = Math.sqrt(dx * dx + dy * dy);

          let offsetX = 0;
          let offsetY = 0;

          // เธ–เนเธฒเธเธธเธ”เธเธตเนเธญเธขเธนเนเนเธเธฅเนเน€เธกเธฒเธชเน เนเธซเนเธเธฅเธฑเธเธกเธฑเธเธญเธญเธ
          if (dist < radius) {
            let force = Math.pow((radius - dist) / radius, 2);
            offsetX = -dx * force * tension;
            offsetY = -dy * force * tension;
          }

          if (x === 0) ctx.moveTo(x + offsetX, y + offsetY);
          else ctx.lineTo(x + offsetX, y + offsetY);
        }
        ctx.stroke();
      }

      // โ”€โ”€โ”€ เธงเธฒเธ”เน€เธชเนเธเนเธเธงเธ•เธฑเนเธ โ”€โ”€โ”€
      for (let x = 0; x <= width + spacing; x += spacing) {
        ctx.beginPath();
        for (let y = 0; y <= height + 20; y += 20) {
          let dx = mouse.x - x;
          let dy = mouse.y - y;
          let dist = Math.sqrt(dx * dx + dy * dy);

          let offsetX = 0;
          let offsetY = 0;

          if (dist < radius) {
            let force = Math.pow((radius - dist) / radius, 2);
            offsetX = -dx * force * tension;
            offsetY = -dy * force * tension;
          }

          if (y === 0) ctx.moveTo(x + offsetX, y + offsetY);
          else ctx.lineTo(x + offsetX, y + offsetY);
        }
        ctx.stroke();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      container.removeEventListener("mousemove", handleMouseMove);
      container.removeEventListener("mouseleave", handleMouseLeave);
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  return (
    <div
      ref={containerRef}
      className="relative w-full overflow-hidden bg-[#eeeeee]"
    >
      {/* เธเธทเธเธเนเธฒเนเธเธงเธฒเธ”เน€เธชเนเธเธ•เธฒเธฃเธฒเธ (เธงเธฒเธเนเธงเนเธซเธฅเธฑเธเธชเธธเธ” z-0) */}
      <canvas
        ref={canvasRef}
        className="absolute inset-0 z-0 pointer-events-none"
      />

      {/* เน€เธเธทเนเธญเธซเธฒเธ”เนเธฒเธเธเธ (เธเธธเนเธกเธเธ” เธเธญเธฃเนเธกเธ•เนเธฒเธเน เธขเธฑเธเธ—เธณเธเธฒเธเนเธ”เนเธเธเธ•เธดเน€เธเธฃเธฒเธฐเธญเธขเธนเน z-10) */}
      <div className="relative z-10 w-full">{children}</div>
    </div>
  );
}

