  const mapInstance = useRef(null);

  useEffect(() => {
    // เธเนเธญเธเธเธฑเธเธเธฒเธฃ render เนเธเธเธ—เธตเนเธเนเธณ
    if (!mapRef.current || mapInstance.current) return;

    const map = L.map(mapRef.current).setView([13.913, 100.498], 14);
    mapInstance.current = map;

    L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
      maxZoom: 19,
      attribution: "ยฉ OpenStreetMap",
    }).addTo(map);

    const kfcIcon = L.icon({
      iconUrl:
        "https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-red.png",
      shadowUrl:
        "https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png",
      iconSize: [25, 41],
      iconAnchor: [12, 41],
      popupAnchor: [1, -34],
    });

    // เธชเธฃเนเธฒเธเธเธธเนเธกเธเธ Popup เนเธเธ DOM Element เน€เธเธทเนเธญเธเธนเธ Event Listener เธเธญเธ React เนเธ”เน
    const createPopupContent = (branchName) => {
      const div = document.createElement("div");
      div.className = "text-center font-sans";
      div.innerHTML = `<b class="text-brand-black text-sm">KFC เธชเธฒเธเธฒ ${branchName}</b><br>`;

      const btn = document.createElement("button");
      btn.className =
        "mt-2 bg-brand-red text-white px-3 py-1 rounded text-xs hover:bg-red-800";
      btn.innerText = "เน€เธฅเธทเธญเธเธชเธฒเธเธฒเธเธตเน";
      btn.onclick = () => onSelectBranch(branchName); // เน€เธฃเธตเธขเธ Props

      div.appendChild(btn);
      return div;
    };

    L.marker([13.9008, 100.4983], { icon: kfcIcon })
      .addTo(map)
      .bindPopup(createPopupContent("เนเธฅเธ•เธฑเธช เธเธฒเธเน€เธเธฃเนเธ”"));

    L.marker([13.9085, 100.499], { icon: kfcIcon })
      .addTo(map)
      .bindPopup(createPopupContent("เน€เธกเน€เธเธญเธฃเน เธฎเธญเธฅเธฅเธตเธงเธนเธ” เธเธฒเธเน€เธเธฃเนเธ”"));

    // Cleanup เน€เธกเธทเนเธญ Component เธ–เธนเธเธ—เธณเธฅเธฒเธข
    return () => {
      map.remove();
      mapInstance.current = null;
    };
  }, [onSelectBranch]);

  return (
    <div
      ref={mapRef}
      className="w-full h-100 border-4 border-brand-black rounded shadow-lg z-10"
    />
  );
}

