import { ShopContext } from "../../context/ShopProvider";
import { orderService } from "../../services/orderService";
import { paymentService } from "../../services/paymentService";

export default function OrderSummary({ cartItems, bookingData }) {
  const navigate = useNavigate();
  const [promoCode, setPromoCode] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);

  const { myUserInfo } = useContext(UserContext);
  const { paymentState } = useContext(PaymentContext);
  const { setCart } = useContext(ShopContext);

  // เธเธณเธเธงเธ“เธขเธญเธ”เน€เธเธดเธเธฃเธงเธก (เนเธเน item.quantity เนเธ—เธ item.qty)
  const subtotal = cartItems.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);
  const tax = subtotal * 0.07; // 7% VAT
  const discount = 0; // เธเธณเธฅเธญเธเธชเนเธงเธเธฅเธ”
  const deliveryFee = 0; // เธเธฃเธตเธเนเธฒเธเธฑเธ”เธชเนเธ
  const total = subtotal + tax - discount + deliveryFee;

  const handleOrderAndPay = async () => {
    if (cartItems.length === 0) {
      alert("เธเธฃเธธเธ“เธฒเน€เธฅเธทเธญเธเธชเธดเธเธเนเธฒเธเนเธญเธเธเธณเธฃเธฐเน€เธเธดเธ");
      return;
    }

    if (!myUserInfo) {
      alert("เธเธฃเธธเธ“เธฒเน€เธเนเธฒเธชเธนเนเธฃเธฐเธเธเธเนเธญเธเธชเธฑเนเธเธเธทเนเธญ");
      navigate("/login");
      return;
    }

    setIsProcessing(true);
    try {
      const profile = bookingData?.profile || {};
      const orderType = bookingData?.type === "Delivery" ? "delivery" : "Onsite";
      const customerAddress = bookingData?.userAddress || bookingData?.branch || "Asok Branch (HQ)";

      // 1. Create order in backend
      const orderData = {
        type: orderType,
        customer: {
          name: profile.name || myUserInfo.name,
          contact: profile.contact || myUserInfo.phone || "081-234-5678",
          address: customerAddress,
          note: [
            bookingData?.bookingDate ? `Date: ${bookingData.bookingDate}` : null,
            bookingData?.bookingTime ? `Time: ${bookingData.bookingTime}` : null,
            bookingData?.branch ? `Branch: ${bookingData.branch}` : null,
          ].filter(Boolean).join(" | ") || "None"
        },
        orderList: cartItems.map(item => ({
          name: item.name,
          quantity: item.quantity || item.qty || 1,
          price: item.price,
          image: item.image || item.img || "",
          status: "InKitchen"
        }))
      };

      const newOrder = await orderService.createOrder(orderData);

      // 2. Process payment (mock)
      const paymentDetails = {
        paymentMethod: paymentState.selectedPaymentMethod || "cash",
        amount: total
      };

      await paymentService.processPayment(newOrder._id, paymentDetails);

      // 3. Clear cart and redirect
      setCart([]);
      localStorage.removeItem("crispyCart");

      alert("เธชเธฑเนเธเธเธทเนเธญเธชเธณเน€เธฃเนเธ! เธเธณเธฅเธฑเธเธเธณเธเธธเธ“เนเธเธขเธฑเธเธซเธเนเธฒเธ•เธดเธ”เธ•เธฒเธกเธชเธ–เธฒเธเธฐ");
      navigate("/order-tracking", { state: { orderId: newOrder._id, order: newOrder } });

    } catch (error) {
      console.error("Payment failed:", error);
      alert("เน€เธเธดเธ”เธเนเธญเธเธดเธ”เธเธฅเธฒเธ”เนเธเธเธฒเธฃเธเธณเธฃเธฐเน€เธเธดเธ: " + error.message);
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="sticky top-24 bg-[#262626] rounded-xl p-6 shadow-lg border border-gray-700 text-white">
      <h2 className="text-xl font-bold mb-4">เธชเธฃเธธเธเธเธณเธชเธฑเนเธเธเธทเนเธญ</h2>

      {/* Item List */}
      <div className="space-y-3 mb-6">
        {cartItems.length === 0 ? (
          <p className="text-sm text-gray-400">เนเธกเนเธกเธตเธฃเธฒเธขเธเธฒเธฃเธญเธฒเธซเธฒเธฃ</p>
        ) : (
          cartItems.map(item => (
            <div key={item.id} className="flex justify-between text-sm text-gray-300">
              <span>{item.name} ร— {item.quantity}</span>
              <span>เธฟ{(item.price * item.quantity).toLocaleString()}</span>
            </div>
          ))
        )}
      </div>

      {/* Promo Code Input */}
      <div className="flex items-center bg-[#1a1a1a] border border-gray-600 rounded-lg p-1 mb-6">
        <span className="px-3 text-[#DC5F00]">๐ท๏ธ</span>
        <input 
          type="text" 
          placeholder="เนเธเนเธ”เธชเนเธงเธเธฅเธ”" 
          value={promoCode}
          onChange={(e) => setPromoCode(e.target.value)}
          className="w-full bg-transparent text-white focus:outline-none text-sm p-2" 
        />
        <button className="text-[#DC5F00] font-bold px-4 hover:underline">เนเธเน</button>
      </div>

      {/* Totals */}
      <div className="space-y-3 border-b border-gray-600 pb-4 mb-4 text-sm">
        <div className="flex justify-between">
          <span className="text-gray-400">เธฃเธฒเธเธฒเธญเธฒเธซเธฒเธฃ</span>
          <span>เธฟ{subtotal.toLocaleString()}</span>
        </div>
        <div className="flex justify-between">
          <span className="text-gray-400">เธ เธฒเธฉเธต (7%)</span>
          <span>เธฟ{tax.toLocaleString()}</span>
        </div>
        <div className="flex justify-between">
          <span className="text-gray-400">เธเนเธฒเธเธฑเธ”เธชเนเธ</span>
          <span className="text-green-500">เธเธฃเธต</span>
        </div>
        <div className="flex justify-between">
          <span className="text-gray-400">เธชเนเธงเธเธฅเธ”</span>
          <span className="text-red-500">-เธฟ{discount}</span>
        </div>
      </div>

      <div className="flex justify-between font-bold text-lg mb-6">
        <span>เธขเธญเธ”เธฃเธงเธก</span>
        <span className="text-[#DC5F00]">เธฟ{total.toLocaleString()}</span>
      </div>

      {/* Trust Badges */}
      <div className="grid grid-cols-3 gap-2 text-center text-[10px] text-gray-400 mb-6">
        <div>๐”’ เธเธฅเธญเธ”เธ เธฑเธข SSL</div>
        <div>โฑ๏ธ เธเธฑเธ”เธชเนเธเธ”เนเธงเธ</div>
        <div>๐“ เธเธฑเธเธเธญเธฃเนเธ• 24/7</div>
      </div>

      <button 
        onClick={handleOrderAndPay}
        disabled={isProcessing}
        className={`w-full bg-[#DC5F00] hover:bg-[#c25400] text-white font-bold py-4 rounded-lg transition duration-300 flex items-center justify-center gap-2 ${isProcessing ? 'opacity-70 cursor-not-allowed' : ''}`}
      >
        {isProcessing ? (
          <>
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
            เธเธณเธฅเธฑเธเธ”เธณเน€เธเธดเธเธเธฒเธฃ...
          </>
        ) : (
          `เธชเธฑเนเธเธเธทเนเธญเนเธฅเธฐเธเธณเธฃเธฐเน€เธเธดเธ - เธฟ${total.toLocaleString()}`
        )}
      </button>

      <p className="text-center text-xs text-gray-500 mt-4 flex items-center justify-center">
        ๐”’ เธเธณเธฃเธฐเน€เธเธดเธเธเธฅเธญเธ”เธ เธฑเธข - เน€เธเนเธฒเธฃเธซเธฑเธช 256-bit
      </p>
    </div>
  );
}

