            {/* เธเธทเนเธญเนเธฅเธฐเธฃเธฒเธเธฒ */}
            <div className="flex justify-between items-start gap-4 mb-4">
              <h2 className="font-['Bebas_Neue'] text-4xl md:text-5xl text-[#242424] leading-[0.9]">
