              </h2>
              <span className="font-['Bebas_Neue'] text-3xl md:text-4xl text-[#e4002b] shrink-0">
                เธฟ{item.price}
              </span>
            </div>

            {/* เธเธณเธเธฃเธฃเธขเธฒเธขเน€เธ•เนเธก (เธญเนเธฒเธเธชเธเธฒเธขเธ•เธฒ) */}
            <p className="text-[#242424]/80 text-base md:text-lg leading-relaxed mb-6">
              {item.fullDesc || item.desc}
            </p>

            <div className="space-y-6">
              {/* เธชเนเธงเธเธเธชเธก (Ingredients) - เธ—เธณเน€เธเนเธ Pill tags เธเนเธฒเธฃเธฑเธเน */}
