import { useContext, useEffect, useState } from "react";
import { ShoppingBag, Clock, ChevronRight, Package, Calendar, MapPin } from "lucide-react";
import { UserContext } from "../../context/userContext/UserContext";
import { orderService } from "../../services/orderService";

export default function OrderHistoryPage() {
  const { myUserInfo } = useContext(UserContext);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchOrderHistory = async () => {
      setLoading(true);
      try {
        // Assuming orderService.getOrders() or similar exists. 
        // If not, I'll need to check the service or implement it.
        const data = await orderService.getOrders();
        // Filter orders for the current user if the backend doesn't do it
        // But usually, the API should return only user's orders.
        setOrders(data || []);
      } catch (err) {
        setError(err.message || "Failed to load order history");
      } finally {
        setLoading(false);
      }
    };

    fetchOrderHistory();
  }, []);

  const getStatusColor = (status) => {
    switch (status?.toUpperCase()) {
      case "COMPLETED":
      case "DELIVERED":
        return "bg-green-500";
      case "PENDING":
      case "PREPARING":
        return "bg-yellow-500";
      case "CANCELLED":
        return "bg-red-500";
      default:
        return "bg-blue-500";
    }
  };

  return (
    <div className="min-h-screen bg-[#eeeeee] px-4 py-10 font-['IBM_Plex_Sans_Thai'] text-[#242424]">
