                <div className="mt-4 flex flex-wrap gap-2">
                  {order.orderList?.slice(0, 3).map((item, idx) => (
                    <span key={idx} className="rounded-lg border-2 border-[#242424] bg-[#eeeeee] px-3 py-1 text-xs font-bold">
                      {item.quantity}x {item.name}
