  });
  const [, setTick] = useState(0); // เธชเธณเธซเธฃเธฑเธเนเธซเนเน€เธงเธฅเธฒเน€เธ”เธดเธ

  // เธเธณเนเธเธฅเธ•เนเธฒเธเน
  const statusLabel = {
    FREE: "เธงเนเธฒเธ",
    OCCUPIED: "เธกเธตเธฅเธนเธเธเนเธฒ",
    BILL: "เธฃเธญเธเธณเธฃเธฐ",
