  // เธ—เธณเนเธซเนเน€เธงเธฅเธฒเน€เธ”เธดเธเธ—เธธเธ 1 เธงเธดเธเธฒเธ—เธต
  useEffect(() => {
    const timer = setInterval(() => setTick((t) => t + 1), 1000);
