  }, []);

  // Responsive: เธเธฃเธฑเธเธกเธธเธกเธกเธญเธเธญเธฑเธ•เนเธเธกเธฑเธ•เธดเน€เธกเธทเนเธญเธเธญเน€เธฅเนเธ
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth <= 768 && currentView === "floor")
        setCurrentView("list");
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
