  const handleUpdateStatus = (id, newStatus) => {
    setTables(
      tables.map((t) => {
        if (t.id === id) {
          return {
            ...t,
            status: newStatus,
            startTime:
              newStatus === "OCCUPIED"
                ? Date.now()
